import React from 'react';
import {
  LayoutDashboard,
  Server,
  Terminal,
  HardDrive,
  FileText,
  Activity,
  Cpu,
  MemoryStick,
  ExternalLink,
  Menu,
  X,
  Settings,
  Users
} from 'lucide-react';

function Sidebar({ activeTab, onTabChange, serverHealth }) {
  const [mobileOpen, setMobileOpen] = React.useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'inventory', label: 'Inventário', icon: Server },
    { id: 'terminal', label: 'Terminal SSH', icon: Terminal },
    { id: 'backups', label: 'Backups', icon: HardDrive },
    { id: 'audit', label: 'Logs', icon: FileText },
    { id: 'settings', label: 'Configurações', icon: Settings },
  ];

  const externalLinks = [
    { label: 'LibreNMS', url: '/librenms/' },
    { label: 'phpIPAM', url: '/phpipam/' },
    { label: 'Admin Django', url: '/admin/' },
  ];

  const health = serverHealth || { cpu: 0, ram: 0, disk: 0 };

  const NavContent = () => (
    <>
      {/* Logo */}
      <div className="p-4 border-b border-border">
        <h1 className="text-xl font-bold text-primary">LOR CGR</h1>
        <p className="text-xs text-muted-foreground">Network Management</p>
      </div>

      {/* Menu */}
      <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
        {menuItems.map((item) => {
          const Icon = item.icon;
          const isActive = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => { onTabChange(item.id); setMobileOpen(false); }}
              className={
                'w-full flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ' +
                (isActive
                  ? 'bg-primary text-white'
                  : 'text-muted-foreground hover:bg-secondary hover:text-foreground')
              }
            >
              <Icon className="h-5 w-5" />
              {item.label}
            </button>
          );
        })}
      </nav>

      {/* Server Health */}
      <div className="p-4 border-t border-border space-y-3">
        <div className="text-xs font-medium text-muted-foreground uppercase">Servidor</div>
        <div className="space-y-2">
          <div className="flex items-center justify-between text-sm">
            <span className="flex items-center gap-2"><Cpu className="h-4 w-4" /> CPU</span>
            <span className={health.cpu > 80 ? 'text-red-500' : 'text-green-500'}>{health.cpu?.toFixed(1)}%</span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="flex items-center gap-2"><MemoryStick className="h-4 w-4" /> RAM</span>
            <span className={health.ram > 80 ? 'text-red-500' : 'text-green-500'}>{health.ram?.toFixed(1)}%</span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="flex items-center gap-2"><HardDrive className="h-4 w-4" /> Disco</span>
            <span className={health.disk > 80 ? 'text-red-500' : 'text-green-500'}>{health.disk?.toFixed(1)}%</span>
          </div>
        </div>
      </div>

      {/* External Links */}
      <div className="p-4 border-t border-border space-y-2">
        <div className="text-xs font-medium text-muted-foreground uppercase">Links</div>
        {externalLinks.map((link) => (
          <a
            key={link.label}
            href={link.url}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center justify-between px-3 py-2 text-sm text-muted-foreground hover:text-foreground rounded-lg hover:bg-secondary"
          >
            {link.label}
            <ExternalLink className="h-4 w-4" />
          </a>
        ))}
      </div>
    </>
  );

  return (
    <>
      {/* Mobile Header */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-40 bg-card border-b border-border flex items-center justify-between p-4">
        <h1 className="text-lg font-bold text-primary">LOR CGR</h1>
        <button onClick={() => setMobileOpen(!mobileOpen)}>
          {mobileOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
        </button>
      </div>

      {/* Mobile Sidebar */}
      {mobileOpen && (
        <div className="lg:hidden fixed inset-0 z-30 bg-background" onClick={() => setMobileOpen(false)}>
          <aside className="w-64 h-full bg-card border-r border-border flex flex-col" onClick={(e) => e.stopPropagation()}>
            <NavContent />
          </aside>
        </div>
      )}

      {/* Desktop Sidebar */}
      <aside className="hidden lg:flex w-64 min-h-screen bg-card border-r border-border flex-col">
        <NavContent />
      </aside>
    </>
  );
}

export default Sidebar;
